"""
report_generator.py — turn the NZ-govt-AI RAG pipeline into a sourced PDF briefing.

Design principles (this is a Yantra *capability demo* — provenance is the point):
  * Every narrative section is generated by the local Granite model over RETRIEVED
    context only, and records which corpus sources it drew on.
  * Tables and charts are built ONLY from numbers/facts EXTRACTED from the corpus,
    never invented. A small structured-extraction step pulls candidate figures and
    each one carries the source filename it came from.
  * Images are the figures Docling already extracted from the source PDFs, re-placed
    in the report with their captions and source.
  * The PDF shows its working: per-section source notes, figure/table source lines,
    and a References section. That auditability is the selling point.

This module is imported by the notebook. It expects the notebook to have already
built `retriever`, `model` (ChatOllama), and `pictures`/`conversions` from Docling.
Pass those in via `ReportContext` so this file stays import-safe with no globals.
"""
from __future__ import annotations

import io
import os
import re
import json
import datetime
from dataclasses import dataclass, field
from typing import Callable

# ReportLab (PDF assembly)
from reportlab.lib.pagesizes import A4
from reportlab.lib.units import mm
from reportlab.lib import colors
from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
from reportlab.lib.enums import TA_LEFT, TA_CENTER
from reportlab.platypus import (
    SimpleDocTemplate, Paragraph, Spacer, PageBreak, Table, TableStyle,
    Image as RLImage, HRFlowable,
)

# ----------------------------------------------------------------------------
# Brand / styling — Yantra NZ
# ----------------------------------------------------------------------------
YANTRA_INK = colors.HexColor("#0B2545")     # deep navy
YANTRA_ACCENT = colors.HexColor("#13A89E")  # teal
YANTRA_GREY = colors.HexColor("#5A6B7B")
YANTRA_LIGHT = colors.HexColor("#EEF3F6")


def _styles():
    ss = getSampleStyleSheet()
    ss.add(ParagraphStyle("YTitle", parent=ss["Title"], textColor=YANTRA_INK,
                          fontSize=24, leading=28, spaceAfter=6))
    ss.add(ParagraphStyle("YSub", parent=ss["Normal"], textColor=YANTRA_GREY,
                          fontSize=11, leading=15, spaceAfter=2))
    ss.add(ParagraphStyle("YH1", parent=ss["Heading1"], textColor=YANTRA_INK,
                          fontSize=15, leading=19, spaceBefore=14, spaceAfter=6))
    ss.add(ParagraphStyle("YBody", parent=ss["Normal"], fontSize=10.5, leading=15,
                          spaceAfter=8, alignment=TA_LEFT))
    ss.add(ParagraphStyle("YSource", parent=ss["Normal"], fontSize=8,
                          textColor=YANTRA_GREY, leading=11, spaceAfter=10))
    ss.add(ParagraphStyle("YCaption", parent=ss["Normal"], fontSize=8.5,
                          textColor=YANTRA_GREY, leading=11, alignment=TA_CENTER,
                          spaceBefore=3, spaceAfter=12))
    ss.add(ParagraphStyle("YRef", parent=ss["Normal"], fontSize=9, leading=13,
                          spaceAfter=4))
    return ss


# ----------------------------------------------------------------------------
# Context passed in from the notebook
# ----------------------------------------------------------------------------
@dataclass
class ReportContext:
    """Everything the generator needs, injected from the notebook."""
    retriever: object                       # vector_db.as_retriever(...)
    model: object                           # ChatOllama generation model
    conversions: dict                       # {filename: docling_document}
    pictures: list                          # list[Document] image captions
    workdir: str = "."                      # where to write temp + output
    extract_images: bool = True             # place corpus figures in the report


@dataclass
class Section:
    heading: str
    query: str


@dataclass
class _Built:
    heading: str
    text: str
    sources: list[str] = field(default_factory=list)


# ----------------------------------------------------------------------------
# 1. Narrative sections — generated over retrieved context only
# ----------------------------------------------------------------------------
def _rag_section(ctx: ReportContext, query: str, k: int = 6) -> _Built:
    docs = ctx.retriever.invoke(query)
    context = "\n\n".join(f"[{d.metadata.get('source','?')}] {d.page_content}" for d in docs)
    prompt = (
        "You are writing one section of a briefing on New Zealand government AI "
        "policy for a professional audience. Using ONLY the context below, write "
        "2-4 concise paragraphs answering the prompt. Do not invent facts. If the "
        "context is insufficient, say what is and isn't covered.\n\n"
        f"Context:\n{context}\n\nPrompt: {query}\n\nSection text:"
    )
    text = ctx.model.invoke(prompt).content.strip()
    sources = sorted({d.metadata.get("source", "?") for d in docs})
    return _Built(heading="", text=text, sources=sources)


# ----------------------------------------------------------------------------
# 2. Structured figure extraction — numbers for tables/charts, with provenance
# ----------------------------------------------------------------------------
_EXTRACT_PROMPT = (
    "From the context below, extract any concrete QUANTITATIVE facts (percentages, "
    "counts, dollar amounts, years-with-values) about AI in New Zealand. Return STRICT "
    "JSON: a list of objects with keys: label (str), value (number), unit (str, e.g. "
    "'%','NZD','count'), year (str or null), source (the [filename] it came from). "
    "Return ONLY JSON, no prose. If none, return [].\n\nContext:\n{context}\n\nJSON:"
)


def _extract_figures(ctx: ReportContext, query: str, k: int = 8) -> list[dict]:
    docs = ctx.retriever.invoke(query)
    context = "\n\n".join(f"[{d.metadata.get('source','?')}] {d.page_content}" for d in docs)
    raw = ctx.model.invoke(_EXTRACT_PROMPT.format(context=context)).content
    # Strip code fences / stray prose, then parse defensively.
    m = re.search(r"\[.*\]", raw, re.DOTALL)
    if not m:
        return []
    try:
        data = json.loads(m.group(0))
    except json.JSONDecodeError:
        return []
    out = []
    for d in data:
        try:
            out.append({
                "label": str(d["label"]),
                "value": float(d["value"]),
                "unit": str(d.get("unit", "")),
                "year": (str(d["year"]) if d.get("year") else None),
                "source": str(d.get("source", "?")).strip("[]"),
            })
        except (KeyError, TypeError, ValueError):
            continue
    return out


def _chart_from_figures(figures: list[dict], outpath: str, title: str) -> str | None:
    """Build a bar chart from extracted numbers. Returns path or None."""
    if len(figures) < 2:
        return None
    import matplotlib
    matplotlib.use("Agg")
    import matplotlib.pyplot as plt

    labels = [f"{f['label']}\n({f['year']})" if f["year"] else f["label"] for f in figures]
    values = [f["value"] for f in figures]
    fig, ax = plt.subplots(figsize=(7, 3.6), dpi=150)
    bars = ax.bar(range(len(values)), values, color="#13A89E")
    ax.set_xticks(range(len(values)))
    ax.set_xticklabels(labels, fontsize=8, rotation=0)
    ax.set_title(title, fontsize=11, color="#0B2545")
    ax.spines[["top", "right"]].set_visible(False)
    for b, v in zip(bars, values):
        ax.text(b.get_x() + b.get_width() / 2, v, f"{v:g}", ha="center",
                va="bottom", fontsize=8, color="#0B2545")
    fig.tight_layout()
    fig.savefig(outpath, bbox_inches="tight")
    plt.close(fig)
    return outpath


# ----------------------------------------------------------------------------
# 3. Corpus images — re-place Docling-extracted figures with captions
# ----------------------------------------------------------------------------
def _save_corpus_images(ctx: ReportContext, max_images: int = 3) -> list[tuple[str, str, str]]:
    """Returns list of (image_path, caption, source)."""
    if not ctx.extract_images:
        return []
    saved = []
    idx = 0
    for source, doc in ctx.conversions.items():
        for picture in getattr(doc, "pictures", []):
            if idx >= max_images:
                return saved
            img = picture.get_image(doc)
            if not img:
                continue
            p = os.path.join(ctx.workdir, f"_fig_{idx}.png")
            img.convert("RGB").save(p)
            # find a caption for this picture from the pictures docs, if present
            cap = next((d.page_content for d in ctx.pictures
                        if d.metadata.get("source") == source), "Figure from source document.")
            cap = (cap[:240] + "…") if len(cap) > 240 else cap
            saved.append((p, cap, source))
            idx += 1
    return saved


# ----------------------------------------------------------------------------
# 4. Assemble the PDF
# ----------------------------------------------------------------------------
def _para(text: str, style) -> Paragraph:
    # ReportLab Paragraph wants minimal HTML; escape stray ampersands/brackets.
    safe = (text.replace("&", "&amp;").replace("<", "&lt;").replace(">", "&gt;"))
    safe = safe.replace("\n\n", "<br/><br/>").replace("\n", " ")
    return Paragraph(safe, style)


def _header_footer(canvas, doc):
    canvas.saveState()
    canvas.setFillColor(YANTRA_INK)
    canvas.rect(0, A4[1] - 6 * mm, A4[0], 6 * mm, fill=1, stroke=0)
    canvas.setFillColor(YANTRA_GREY)
    canvas.setFont("Helvetica", 7.5)
    canvas.drawString(20 * mm, 12 * mm,
                      "Yantra NZ  ·  Generated on-prem (DGX Spark) from public NZ government sources")
    canvas.drawRightString(A4[0] - 20 * mm, 12 * mm, f"Page {doc.page}")
    canvas.restoreState()


DEFAULT_SECTIONS = [
    Section("Executive Summary",
            "Summarise New Zealand's overall strategic approach to artificial intelligence."),
    Section("Guiding Principles",
            "What principles (e.g. OECD principles) underpin NZ's responsible AI approach?"),
    Section("Public Service Governance & Assurance",
            "How does NZ guidance govern AI and GenAI use in the public service, including sensitive data?"),
    Section("Treaty of Waitangi & Māori Perspectives",
            "How are Treaty of Waitangi obligations and Māori perspectives reflected in NZ's AI approach?"),
    Section("Economic Opportunity & Adoption",
            "What does the strategy say about AI adoption rates and economic opportunity across NZ sectors?"),
]


def generate_report(
    ctx: ReportContext,
    title: str = "The New Zealand Government AI Landscape",
    subtitle: str = "A sourced briefing generated on-premises from public sector documents",
    sections: list[Section] | None = None,
    figure_query: str = "AI adoption percentages, investment amounts, and statistics in New Zealand",
    output_filename: str = "NZ_Government_AI_Landscape.pdf",
    progress: Callable[[str], None] = print,
) -> str:
    sections = sections or DEFAULT_SECTIONS
    ss = _styles()
    outpath = os.path.join(ctx.workdir, output_filename)
    story = []

    # --- Cover block ---
    story.append(Spacer(1, 30 * mm))
    story.append(Paragraph(title, ss["YTitle"]))
    story.append(Paragraph(subtitle, ss["YSub"]))
    story.append(Spacer(1, 4))
    story.append(HRFlowable(width="100%", thickness=2, color=YANTRA_ACCENT, spaceAfter=8))
    today = datetime.date.today().strftime("%d %B %Y")
    story.append(Paragraph(
        f"Prepared by Yantra NZ  ·  {today}<br/>"
        "Multimodal RAG over public New Zealand government AI documents. "
        "Generated entirely on local hardware (NVIDIA DGX Spark) using open models — "
        "no document content left the machine.", ss["YSource"]))
    story.append(PageBreak())

    # --- Narrative sections ---
    all_sources: set[str] = set()
    for sec in sections:
        progress(f"  · writing section: {sec.heading}")
        built = _rag_section(ctx, sec.query)
        story.append(Paragraph(sec.heading, ss["YH1"]))
        story.append(_para(built.text, ss["YBody"]))
        if built.sources:
            all_sources.update(built.sources)
            story.append(Paragraph("Sources: " + ", ".join(built.sources), ss["YSource"]))

    # --- Data table + chart from extracted figures ---
    progress("  · extracting quantitative figures for table/chart")
    figures = _extract_figures(ctx, figure_query)
    if figures:
        story.append(PageBreak())
        story.append(Paragraph("Key Figures (extracted from source documents)", ss["YH1"]))
        # table
        header = ["Metric", "Value", "Unit", "Year", "Source"]
        rows = [header] + [[
            f["label"],
            f"{f['value']:g}",
            f["unit"],
            f["year"] or "—",
            f["source"],
        ] for f in figures]
        tbl = Table(rows, repeatRows=1, colWidths=[55*mm, 20*mm, 18*mm, 16*mm, 50*mm])
        tbl.setStyle(TableStyle([
            ("BACKGROUND", (0, 0), (-1, 0), YANTRA_INK),
            ("TEXTCOLOR", (0, 0), (-1, 0), colors.white),
            ("FONTSIZE", (0, 0), (-1, -1), 8.5),
            ("FONTNAME", (0, 0), (-1, 0), "Helvetica-Bold"),
            ("ROWBACKGROUNDS", (0, 1), (-1, -1), [colors.white, YANTRA_LIGHT]),
            ("GRID", (0, 0), (-1, -1), 0.4, colors.HexColor("#CdD7DF")),
            ("VALIGN", (0, 0), (-1, -1), "MIDDLE"),
            ("TOPPADDING", (0, 0), (-1, -1), 4),
            ("BOTTOMPADDING", (0, 0), (-1, -1), 4),
        ]))
        story.append(tbl)
        story.append(Paragraph(
            "Every figure above is extracted verbatim from the cited source document; "
            "none is model-generated.", ss["YCaption"]))
        all_sources.update(f["source"] for f in figures)

        chart_path = _chart_from_figures(
            figures, os.path.join(ctx.workdir, "_chart.png"),
            "Quantitative indicators (from source documents)")
        if chart_path:
            story.append(Spacer(1, 6))
            story.append(RLImage(chart_path, width=160*mm, height=82*mm))
            story.append(Paragraph(
                "Chart built from the extracted figures above.", ss["YCaption"]))

    # --- Corpus figures (Docling-extracted images) ---
    imgs = _save_corpus_images(ctx)
    if imgs:
        story.append(PageBreak())
        story.append(Paragraph("Figures from Source Documents", ss["YH1"]))
        for path, cap, source in imgs:
            try:
                story.append(RLImage(path, width=150*mm, height=90*mm, kind="proportional"))
            except Exception:
                continue
            story.append(Paragraph(f"{cap}<br/><i>Source: {source}</i>", ss["YCaption"]))
            all_sources.add(source)

    # --- References ---
    story.append(PageBreak())
    story.append(Paragraph("References", ss["YH1"]))
    for s in sorted(all_sources):
        story.append(Paragraph(f"• {s}", ss["YRef"]))
    story.append(Spacer(1, 10))
    story.append(Paragraph(
        "This document was assembled automatically by Yantra NZ's local multimodal "
        "RAG pipeline. All narrative is grounded in retrieved passages from the listed "
        "sources; all figures are extracted, not generated.", ss["YSource"]))

    doc = SimpleDocTemplate(
        outpath, pagesize=A4,
        leftMargin=20*mm, rightMargin=20*mm, topMargin=18*mm, bottomMargin=20*mm,
        title=title, author="Yantra NZ",
    )
    doc.build(story, onFirstPage=_header_footer, onLaterPages=_header_footer)
    progress(f"  ✓ wrote {outpath}")
    return outpath
